#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* prev;
    Node* next;
    Node(int d) : data(d), prev(nullptr), next(nullptr) {}
};

void insertFront(Node*& head, int val) {
    Node* newNode = new Node(val);
    if (head) {
        newNode->next = head;
        head->prev = newNode;
    }
    head = newNode;
}

int main() {
    Node* head = nullptr;
    insertFront(head, 30);
    insertFront(head, 20);
    insertFront(head, 10);
    printForward(head); // 10 20 30
    return 0;
}

#include <iostream>
using namespace std;

void insertEnd(Node*& head, int val) {
    Node* newNode = new Node(val);
    if (!head) {
        head = newNode;
        return;
    }
    Node* curr = head;
    while (curr->next) curr = curr->next;
    curr->next = newNode;
    newNode->prev = curr;
}

int main() {
    Node* head = nullptr;
    insertEnd(head, 10);
    insertEnd(head, 20);
    insertEnd(head, 30);
    printForward(head); // 10 20 30
    return 0;
}

#include <iostream>
using namespace std;

void insertAtPosition(Node*& head, int val, int pos) {
    if (pos < 0) return;
    if (pos == 0) { insertFront(head, val); return; }
    Node* curr = head;
    for (int i = 0; i < pos && curr; i++) curr = curr->next;
    if (!curr) return; // position beyond list
    Node* newNode = new Node(val);
    newNode->prev = curr->prev;
    newNode->next = curr;
    if (curr->prev) curr->prev->next = newNode;
    curr->prev = newNode;
}

int main() {
    Node* head = nullptr;
    insertEnd(head, 10); insertEnd(head, 30);
    insertAtPosition(head, 20, 1); // 10 20 30
    printForward(head);
    return 0;
}

#include <iostream>
using namespace std;

void deleteNode(Node*& head, Node* del) {
    if (!head || !del) return;
    if (head == del) head = del->next;
    if (del->prev) del->prev->next = del->next;
    if (del->next) del->next->prev = del->prev;
    delete del;
}

void deleteByValue(Node*& head, int val) {
    Node* curr = head;
    while (curr && curr->data != val) curr = curr->next;
    if (curr) deleteNode(head, curr);
}

int main() {
    Node* head = nullptr;
    insertEnd(head, 10); insertEnd(head, 20); insertEnd(head, 30);
    deleteByValue(head, 20);
    printForward(head); // 10 30
    return 0;
}

#include <iostream>
using namespace std;

void reverse(Node*& head) {
    Node* curr = head;
    Node* temp = nullptr;
    while (curr) {
        temp = curr->prev;
        curr->prev = curr->next;
        curr->next = temp;
        curr = curr->prev; // move to original next
    }
    if (temp) head = temp->prev; // update head
}

int main() {
    Node* head = nullptr;
    insertEnd(head, 1); insertEnd(head, 2); insertEnd(head, 3);
    reverse(head);
    printForward(head); // 3 2 1
    return 0;
}

#include <iostream>
using namespace std;

// Example: delete a node when only given pointer to that node (O(1))
void deleteGivenNode(Node* del) {
    if (!del) return;
    if (del->prev) del->prev->next = del->next;
    if (del->next) del->next->prev = del->prev;
    delete del;
}

int main() {
    Node* head = nullptr;
    insertEnd(head, 1); insertEnd(head, 2); insertEnd(head, 3);
    Node* toDelete = head->next; // points to 2
    deleteGivenNode(toDelete);   // O(1) deletion
    printForward(head); // 1 3
    return 0;
}

